    echo '<!DOCTYPE html><html><head><meta charset="utf-8"><title>PSP Vaardigheden Import</title>';
    echo '<style>body{font-family:sans-serif;max-width:800px;margin:40px auto;padding:20px}.info{background:#d1ecf1;border:1px solid #bee5eb;padding:16px;border-radius:8px;margin:16px 0}.btn{display:inline-block;padding:12px 28px;background:#d31775;color:#fff;border-radius:8px;text-decoration:none;font-weight:700}</style>';
