// Uitvoeren
$ok = 0; $skip = 0; $nieuw_tel = 0;
foreach ($poule_data as [$naam, $email, $telefoon, $vaard_json]) {
    $vaardigheden = json_decode($vaard_json, true) ?: [];
    $wp_user = null;

    // Match op email (primair)
    if ($email) $wp_user = get_user_by('email', $email);

    // Match op display_name (fallback)
    if (!$wp_user && $naam) {
        $users = get_users(['search' => $naam, 'search_columns' => ['display_name']]);
        if ($users) $wp_user = $users[0];
    }

    // similar_text fallback
    if (!$wp_user && $naam) {
        $alle = get_users(['role__in' => ['psp_student', 'psp_aanvraag']]);
        $best = 0; $best_user = null;
        foreach ($alle as $u) {
            similar_text(strtolower($naam), strtolower($u->display_name), $p);
            if ($p > $best) { $best = $p; $best_user = $u; }
        }
        if ($best >= 70) $wp_user = $best_user;
    }

    if (!$wp_user) { $skip++; continue; }

    update_user_meta($wp_user->ID, 'psp_vaardigheden', $vaardigheden);
    if ($telefoon) update_user_meta($wp_user->ID, 'psp_telefoon', $telefoon);
    $ok++;
}

echo '<!DOCTYPE html><html><head><meta charset="utf-8"><title>Klaar</title>';
echo '<style>body{font-family:sans-serif;max-width:800px;margin:40px auto;padding:20px}.ok{background:#d4edda;border:1px solid #28a745;padding:16px;border-radius:8px;margin:8px 0}</style>';
echo '</head><body><h1>Vaardigheden import klaar</h1>';
echo "<div class=ok>✅ Bijgewerkt: {$ok}</div>";
echo "<div class=ok>⚠️ Niet gevonden: {$skip}</div>";
echo "<div class=ok><a href='" . home_url('/planning-dashboard/') . "'>Naar dashboard →</a></div>";
echo '</body></html>';
